#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset) {
    int i, j, k;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = i; j < BLOCK_SIZE; j++) {
            float sum = m[(offset + i) * matrix_dim + (offset + j)];
            for (k = 0; k < i; k++) {
                sum -= m[(offset + i) * matrix_dim + (offset + k)] *
                       m[(offset + k) * matrix_dim + (offset + j)];
            }
            m[(offset + i) * matrix_dim + (offset + j)] = sum;
        }

        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = m[(offset + j) * matrix_dim + (offset + i)];
            for (k = 0; k < i; k++) {
                sum -= m[(offset + j) * matrix_dim + (offset + k)] *
                       m[(offset + k) * matrix_dim + (offset + i)];
            }
            m[(offset + j) * matrix_dim + (offset + i)] =
                sum / m[(offset + i) * matrix_dim + (offset + i)];
        }
    }
}

static void lud_perimeter_omp(float *m, int matrix_dim, int offset) {
    int b;
    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    #pragma omp parallel for private(b) schedule(static)
    for (b = 0; b < num_blocks; b++) {
        int i, j, k;
        int col = offset + (b + 1) * BLOCK_SIZE;
        int row = offset + (b + 1) * BLOCK_SIZE;

        for (i = 1; i < BLOCK_SIZE; i++) {
            for (k = 0; k < BLOCK_SIZE; k++) {
                float sum = m[(offset + i) * matrix_dim + (col + k)];
                for (j = 0; j < i; j++) {
                    sum -= m[(offset + i) * matrix_dim + (offset + j)] *
                           m[(offset + j) * matrix_dim + (col + k)];
                }
                m[(offset + i) * matrix_dim + (col + k)] = sum;
            }
        }

        for (k = 0; k < BLOCK_SIZE; k++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                float sum = m[(row + k) * matrix_dim + (offset + i)];
                for (j = 0; j < i; j++) {
                    sum -= m[(row + k) * matrix_dim + (offset + j)] *
                           m[(offset + j) * matrix_dim + (offset + i)];
                }
                m[(row + k) * matrix_dim + (offset + i)] =
                    sum / m[(offset + i) * matrix_dim + (offset + i)];
            }
        }
    }
}

static void lud_internal_omp(float *m, int matrix_dim, int offset) {
    int bx, by;
    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    #pragma omp parallel for collapse(2) private(by, bx) schedule(static)
    for (by = 0; by < num_blocks; by++) {
        for (bx = 0; bx < num_blocks; bx++) {
            int i, j, k;
            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    float sum = 0.0f;
                    for (k = 0; k < BLOCK_SIZE; k++) {
                        sum += m[(global_row_id + i) * matrix_dim + (offset + k)] *
                               m[(offset + k) * matrix_dim + (global_col_id + j)];
                    }
                    m[(global_row_id + i) * matrix_dim + (global_col_id + j)] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int offset;

    omp_set_dynamic(0);
    omp_set_num_threads(omp_num_threads);

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        lud_diagonal_omp(m, matrix_dim, offset);
        lud_perimeter_omp(m, matrix_dim, offset);
        lud_internal_omp(m, matrix_dim, offset);
    }

    lud_diagonal_omp(m, matrix_dim, offset);
}
